const body = $('Webhook: Receber Solicitação').item.json.body || $('Webhook: Receber Solicitação').item.json;

const formato = body.formato || 'reel';
const tom = body.tom || 'vendas_diretas';
const nichoImovel = body.nicho_imovel || 'terreno';
const angulo = body.angulo || '';
const descricaoImagens = body.descricao_imagens || '';
const callbackUrl = body.callback_url || '';
const jobId = body.job_id || '';

const FORMATO_LABELS = {
  reel: 'Reel (63-90 segundos)',
  carrossel: 'Carrossel',
  stories: 'Sequência de Stories',
  post_estatico: 'Post Estático'
};
const TOM_LABELS = {
  educativo: 'Educativo',
  vendas_diretas: 'Vendas Diretas',
  inspiracional: 'Inspiracional',
  tutorial: 'Tutorial passo a passo'
};
const NICHO_LABELS = {
  terreno: 'Terreno / Lote',
  casa: 'Casa',
  apartamento: 'Apartamento',
  comercial: 'Imóvel Comercial',
  alto_padrao: 'Alto Padrão'
};

const SKILL = `# IMovie Reel Creator — Skill

## Produto
IMovie / iMobCreator é um SaaS imobiliário que transforma fotos de terrenos e imóveis em vídeos cinematográficos profissionais com IA. Sem edição manual, sem cursos. Fluxo: dados → upload → configuração → processamento → vídeo pronto.

## Público-Alvo
Corretores sem habilidade de edição, construtoras, arquitetos, investidores.

## Estrutura do Reel (63-90s)
- Hook (0-3s): frase de impacto
- Problema/Dor (3-15s): realidade do corretor sem vídeo
- Solução/Transformação (15-45s): sequência antes/depois + demo do app
- Prova Social/CTA (45-63s): galeria + CTA claro

## Sequência Visual Ideal
[0-2s] Texto: SEM CURSOS | SEM EDIÇÃO
[2-8s] Foto bruta de terreno (crua, celular)
[8-15s] Wipe transition → render profissional gerado pela IA
[15-25s] Screen recording: formulário simples do app
[25-35s] Barra de progresso — Gerando...
[35-50s] Galeria de projetos criados
[50-63s] Logo IMovie + CTA animado

## Ângulos de Campanha
- economia: Gastei R$0 em edição de vídeo esse mês | Corretor autônomo
- velocidade: Vídeo profissional em 5 minutos | Imobiliária
- resultado: Esse imóvel vendeu em 3 dias com esse vídeo | Todo corretor
- tutorial: Como criar seu primeiro vídeo no IMovie | Iniciantes
- comparacao: Antes foto feia. Depois vídeo cinematográfico | Amplo
- autoridade: O app que corretores profissionais estão usando | Aspiracional

## Hashtags
#CorretoDeImóveis #VideoImobiliário #ImovelDigital #MarketingImobiliário #InteligenciaArtificial #iMobCreator #IMovie #VídeoComIA #CorretoraDigital #ImóveisComIA #VideoProfissional #SemEdição

## Trilha
Corporativo/Tecnológico ou Épico/Cinematográfico — Apple-style. Tom: confiante, inovador, sofisticado.`;

const systemPrompt = `Você é um especialista em marketing de conteúdo para o mercado imobiliário brasileiro.\nUse a skill abaixo como base para gerar conteúdo de alta conversão para o IMovie / iMobCreator.\n\n${SKILL}\n\nResponda APENAS em JSON válido sem markdown nem blocos de código. Estrutura obrigatória:\n{\n  "roteiro_cenas": [{"timecode": "0-2s", "elemento": "...", "descricao": "..."}],\n  "script_narracao": "texto completo da narração em voz off",\n  "legenda_post": "texto completo da legenda com emojis pronta para colar",\n  "hashtags": ["#tag1", "#tag2"],\n  "trilha_sugestao": "descrição do estilo musical",\n  "cta_final": "texto exato do CTA",\n  "hook_principal": "frase de abertura de alto impacto",\n  "angulo_escolhido": "nome do ângulo utilizado"\n}`;

const anguloTexto = angulo
  ? `Ângulo de campanha obrigatório: ${angulo}`
  : 'Ângulo: escolha o mais adequado para máxima conversão com o público deste formato';
const imagensTexto = descricaoImagens
  ? `\nImagens disponíveis para adaptar o roteiro: ${descricaoImagens}`
  : '';

const userPrompt = `Gere um pacote completo de conteúdo IMovie:\n- Formato: ${FORMATO_LABELS[formato] || formato}\n- Tom: ${TOM_LABELS[tom] || tom}\n- Nicho do imóvel: ${NICHO_LABELS[nichoImovel] || nichoImovel}\n- ${anguloTexto}${imagensTexto}\n\nEntregue roteiro de cenas com timecodes adaptado ao formato, script de narração no tom correto, legenda pronta com emojis, hashtags segmentadas, sugestão de trilha e CTA de alta conversão. Tudo em português do Brasil.`;

return [{
  json: {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 3000,
    system: systemPrompt,
    user: userPrompt,
    callback_url: callbackUrl,
    job_id: jobId,
    formato,
    tom,
    nicho_imovel: nichoImovel
  }
}];

const claudeResp = $input.item.json;
const promptCtx = $('Code: Montar Prompt').item.json;

const rawText = claudeResp?.content?.[0]?.text || '';

let pacote = {};
try {
  pacote = JSON.parse(rawText);
} catch(e) {
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) {
    try { pacote = JSON.parse(match[0]); } catch(_) { pacote = { raw: rawText }; }
  } else {
    pacote = { raw: rawText };
  }
}

const usage = claudeResp?.usage || {};

return [{
  json: {
    status: 'completed',
    job_id: promptCtx.job_id,
    formato: promptCtx.formato,
    tom: promptCtx.tom,
    nicho_imovel: promptCtx.nicho_imovel,
    pacote,
    tokens_input: usage.input_tokens || 0,
    tokens_output: usage.output_tokens || 0,
    callback_url: promptCtx.callback_url,
    generated_at: new Date().toISOString()
  }
}];

const err = $input.item.json;
console.error('[imovie-reel-creator] Erro Claude:', JSON.stringify(err));
return [{ json: { status: 'error', error: String(err.message || JSON.stringify(err)), timestamp: new Date().toISOString() } }];
